import{_ as a,o as i,c as t,ag as o}from"./chunks/framework.CAXxHpAX.js";const h=JSON.parse('{"title":"V5 Release Plan — Phases A through E","description":"","frontmatter":{},"headers":[],"relativePath":"superpowers/plans/2026-04-30-v5-release-plan.md","filePath":"superpowers/plans/2026-04-30-v5-release-plan.md","lastUpdated":1777988338000}'),r={name:"superpowers/plans/2026-04-30-v5-release-plan.md"};function l(n,e,s,c,d,u){return i(),t("div",null,[...e[0]||(e[0]=[o(`<h1 id="v5-release-plan-—-phases-a-through-e" tabindex="-1">V5 Release Plan — Phases A through E <a class="header-anchor" href="#v5-release-plan-—-phases-a-through-e" aria-label="Permalink to &quot;V5 Release Plan — Phases A through E&quot;">​</a></h1><blockquote><p><strong>Renamed 2026-05-03</strong> — see <a href="./2026-05-03-zkqes-rename-design"><code>docs/superpowers/specs/2026-05-03-zkqes-rename-design.md</code></a> for the rename baseline. Historical references to QKB/QIE/Identity-Escrow in pre-2026-05-03 commits remain immutable in git history.</p></blockquote><p><strong>Date:</strong> 2026-04-30 <strong>Status:</strong> Drafted post-A1-implementation-complete <strong>Spec:</strong> <a href="./../specs/2026-04-29-v5-architecture-design"><code>2026-04-29-v5-architecture-design.md</code></a> at HEAD <code>def6270</code><strong>Predecessor:</strong> A1 V5 architecture (functionally complete; circuit + SDK + web + contracts + flattener all green) <strong>Total wall estimate:</strong> ~3-4 weeks to Sepolia public launch · ~5-6 weeks to Base mainnet</p><hr><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>V5 architecture implementation is complete. What remains is the production rollout sequence: trusted-setup ceremony → live deploy → acceptance gate → frontend cutover → public launch. This plan covers the path from &quot;implementation done&quot; to &quot;public launch on Sepolia,&quot; with mainnet as a separately-gated follow-on (Phase F).</p><p>The critical path runs through the multi-contributor Phase 2 ceremony (1-2 weeks), which the founder will recruit personally. Everything else is bounded engineering work.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Phase A (prep, parallel, ~5 days)</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>        ▼</span></span>
<span class="line"><span>Phase B (ceremony, ~1-2 weeks wall)</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>        ▼</span></span>
<span class="line"><span>Phase C (deploy, ~2-3 days)</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>        ▼</span></span>
<span class="line"><span>Phase D (acceptance gate, ~1 day)</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>        ▼</span></span>
<span class="line"><span>Phase E (cutover + launch, ~3-5 days)</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>        ▼</span></span>
<span class="line"><span>[Sepolia public stable ≥ 1 week]</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>        ▼</span></span>
<span class="line"><span>Phase F (Base mainnet, separately gated)</span></span></code></pre></div><hr><h2 id="phase-a-—-pre-ceremony-prep" tabindex="-1">Phase A — Pre-ceremony prep <a class="header-anchor" href="#phase-a-—-pre-ceremony-prep" aria-label="Permalink to &quot;Phase A — Pre-ceremony prep&quot;">​</a></h2><p><strong>Goal:</strong> Stand up coordination infrastructure + recruit ceremony contributors. Block before kicking off Phase B.</p><p><strong>Wall estimate:</strong> 3-5 days, all tasks parallel-able.</p><h3 id="a1-ceremony-coordination-page-web-eng" tabindex="-1">A1. /ceremony coordination page (web-eng) <a class="header-anchor" href="#a1-ceremony-coordination-page-web-eng" aria-label="Permalink to &quot;A1. /ceremony coordination page (web-eng)&quot;">​</a></h3><ul><li>Owner: <code>web-eng</code></li><li>Tracker: Task #27 (in flight)</li><li>Deliverables: <ul><li>4 routes: landing / contribute / status / verify</li><li>Civic-monumental aesthetic, EN + UK i18n</li><li>PC-flow instructions with copy-buttons (32 GB RAM requirement explicit)</li><li>Tri-state JSON-backed status feed (polled from R2 every 30s)</li><li>Browser-side sha256 verify-post-ceremony (Web Worker via <code>@noble/hashes</code>)</li><li>Playwright e2e for three states (not-started / in-progress / complete)</li></ul></li><li>Acceptance: 4/4 routes render civically on desktop + flagship mobile, all PC commands have copy-buttons, status JSON tri-state handled cleanly, Playwright green.</li></ul><h3 id="a2-r2-ceremony-bucket-coordination-scripts-lead" tabindex="-1">A2. R2 ceremony bucket + coordination scripts (lead) <a class="header-anchor" href="#a2-r2-ceremony-bucket-coordination-scripts-lead" aria-label="Permalink to &quot;A2. R2 ceremony bucket + coordination scripts (lead)&quot;">​</a></h3><ul><li>Owner: <code>team-lead</code></li><li>New task to create</li><li>Deliverables: <ul><li>R2 bucket <code>prove.zkqes.org/ceremony/</code> with public-read on artifacts + signed-write for uploads</li><li>Per-round signed upload URL generator script</li><li>Per-round download URL publisher</li><li><code>status.json</code> publisher (admin updates manually after each contribution lands)</li><li>Per-contribution verification script: <code>snarkjs zkey verify</code> against the previous chain link</li><li>Round-0 zkey (admin&#39;s own contribution as the chain seed)</li></ul></li><li>Acceptance: signed-URL upload round-trips successfully with a test 2.2 GB file; verification script catches a tampered zkey; status.json renders correctly in web-eng&#39;s <code>/ceremony/status</code>.</li></ul><h3 id="a3-contributor-recruitment-founder-driven" tabindex="-1">A3. Contributor recruitment (founder-driven) <a class="header-anchor" href="#a3-contributor-recruitment-founder-driven" aria-label="Permalink to &quot;A3. Contributor recruitment (founder-driven)&quot;">​</a></h3><ul><li>Owner: <code>founder</code> (handled personally)</li><li>Out of scope for engineering team</li><li>Target: 7-10 trusted core contributors</li><li>Likely outreach pool: PSE, 0xPARC, Mopro, Anon Aadhaar team, Polygon ID, Worldcoin alumni, Lambdaclass, ETH Kyiv, individual ZK researchers</li><li>No formal task; founder reports back when contributor list is confirmed</li><li>Phase B can begin with as few as 5 confirmed contributors; later contributors can join mid-chain</li></ul><h3 id="a4-ceremony-copy-tease-tweet-marketer" tabindex="-1">A4. Ceremony copy + tease tweet (marketer) <a class="header-anchor" href="#a4-ceremony-copy-tease-tweet-marketer" aria-label="Permalink to &quot;A4. Ceremony copy + tease tweet (marketer)&quot;">​</a></h3><ul><li>Owner: <code>marketer</code></li><li>New task to dispatch</li><li>Deliverables: <ul><li>Sign-up email template (founder uses verbatim or adapts per contact)</li><li>Twitter/X announcement thread (separate from launch thread; goes out after 5+ contributors confirmed)</li><li>One-line tease for the project&#39;s social profile</li></ul></li><li>Acceptance: drafts saved under <code>docs/marketing/2026-04-30-ceremony-drafts/</code>. No publishing pre-Phase-B-kickoff.</li></ul><h3 id="phase-a-gate-to-phase-b" tabindex="-1">Phase A gate to Phase B <a class="header-anchor" href="#phase-a-gate-to-phase-b" aria-label="Permalink to &quot;Phase A gate to Phase B&quot;">​</a></h3><ul><li>A1 shipped + Playwright e2e green (3/3 states)</li><li>A2 shipped: signed-URL round-trip works + verification script catches tampered zkey</li><li>A3: 5+ contributors confirmed (founder reports back)</li><li>A4 drafts saved</li></ul><hr><h2 id="phase-b-—-ceremony-runs" tabindex="-1">Phase B — Ceremony runs <a class="header-anchor" href="#phase-b-—-ceremony-runs" aria-label="Permalink to &quot;Phase B — Ceremony runs&quot;">​</a></h2><p><strong>Goal:</strong> Execute the 7-10 contributor Phase 2 ceremony. Produce final production zkey + auto-generated verifier.sol.</p><p><strong>Wall estimate:</strong> 7-14 days. Sequential per contributor (1/day average), with admin verification between each.</p><h3 id="b1-round-0-lead-s-seed-contribution" tabindex="-1">B1. Round-0 (lead&#39;s seed contribution) <a class="header-anchor" href="#b1-round-0-lead-s-seed-contribution" aria-label="Permalink to &quot;B1. Round-0 (lead&#39;s seed contribution)&quot;">​</a></h3><ul><li>Owner: <code>team-lead</code> + <code>circuits-eng</code></li><li>Deliverables: <ul><li>circuits-eng generates round-0 zkey from V5 main 4.02M-constraint R1CS + pot23 ptau (already done at §8 stub, but re-run for production canonical chain)</li><li>Lead applies admin entropy as round-0 contribution</li><li>Upload to R2 round-0 endpoint</li><li>Update status.json: round=1, totalRounds=N, contributors=[admin]</li></ul></li><li>Acceptance: round-0 zkey verifies against R1CS + ptau via <code>snarkjs zkey verify</code>; status.json published.</li></ul><h3 id="b2-per-contribution-loop-b2-1-through-b2-n-where-n-7-10" tabindex="-1">B2. Per-contribution loop (B2.1 through B2.N, where N = ~7-10) <a class="header-anchor" href="#b2-per-contribution-loop-b2-1-through-b2-n-where-n-7-10" aria-label="Permalink to &quot;B2. Per-contribution loop (B2.1 through B2.N, where N = ~7-10)&quot;">​</a></h3><p>For each contributor in turn:</p><ol><li><strong>Founder</strong> notifies the contributor that their round is open (via DM with their signed-upload URL pre-filled)</li><li><strong>Contributor</strong> runs the 4-command flow (download → contribute → verify → upload). ~15-20 min wall.</li><li><strong>Lead</strong> verifies the uploaded zkey: <ul><li>Verify against R1CS + ptau</li><li>Verify chain integrity (this contribution builds on previous)</li><li>Compute attestation hash</li></ul></li><li><strong>Lead</strong> publishes the contribution to status.json (name, attestation, completedAt)</li><li><strong>Lead</strong> signals next contributor&#39;s round is open</li></ol><p>If a contribution fails verification (rare — usually ABI mismatch or transmission error): lead requests re-do; doesn&#39;t break chain.</p><p>If a contributor goes silent for &gt;48h: lead skips, founder recruits a replacement.</p><h3 id="b3-beacon" tabindex="-1">B3. Beacon <a class="header-anchor" href="#b3-beacon" aria-label="Permalink to &quot;B3. Beacon&quot;">​</a></h3><ul><li>Owner: <code>team-lead</code></li><li>After last individual contribution lands: <ul><li>Pin a future Ethereum block (typically +24h after last contribution)</li><li>When that block lands, use its hash as the final ceremony entropy via <code>snarkjs zkey beacon</code></li><li>Publishes the beacon block height + hash + final zkey sha256</li></ul></li><li>Trust: beacon block hash is cryptographically committed before any participant could grind it; binds setup to public timestamp</li><li>Acceptance: beacon block confirmed, final zkey sha256 published, beacon proof saved to repo</li></ul><h3 id="b4-finalize-publish-artifacts" tabindex="-1">B4. Finalize + publish artifacts <a class="header-anchor" href="#b4-finalize-publish-artifacts" aria-label="Permalink to &quot;B4. Finalize + publish artifacts&quot;">​</a></h3><ul><li>Owner: <code>team-lead</code> + <code>circuits-eng</code></li><li>Deliverables to commit / publish: <ul><li><code>Groth16VerifierV5.sol</code> (auto-generated from final zkey, drop-in replacement for <code>Groth16VerifierV5Stub.sol</code>)</li><li><code>verification_key.json</code></li><li><code>qkb-v5-final.zkey</code> uploaded to R2 production URL <code>prove.zkqes.org/qkb-v5-final.zkey</code></li><li><code>zkey.sha256</code> integrity reference</li><li>Attestation chain (every contributor + their hash) committed to <code>packages/circuits/ceremony/v5/contribution-log.md</code></li><li>Beacon attestation: <code>packages/circuits/ceremony/v5/beacon-attestation.md</code></li></ul></li><li>Acceptance: <code>groth16.verify</code> succeeds against final zkey + sample (witness, public, proof) triple; verifier.sol forge-compiles; all artifacts public.</li></ul><h3 id="phase-b-gate-to-phase-c" tabindex="-1">Phase B gate to Phase C <a class="header-anchor" href="#phase-b-gate-to-phase-c" aria-label="Permalink to &quot;Phase B gate to Phase C&quot;">​</a></h3><ul><li>All N rounds verified + published in status.json</li><li>Beacon applied + verified</li><li>Final zkey + verifier.sol + verification_key.json published</li><li>Attestation chain complete</li><li>Final zkey forge-builds against the V5 register contract test suite (smoke check before live deploy)</li></ul><hr><h2 id="phase-c-—-post-ceremony-deploy-base-sepolia" tabindex="-1">Phase C — Post-ceremony deploy (Base Sepolia) <a class="header-anchor" href="#phase-c-—-post-ceremony-deploy-base-sepolia" aria-label="Permalink to &quot;Phase C — Post-ceremony deploy (Base Sepolia)&quot;">​</a></h2><p><strong>Goal:</strong> Live-deploy V5 contracts to Base Sepolia with the production verifier.</p><p><strong>Wall estimate:</strong> 2-3 days, mostly sequential within the deploy itself.</p><h3 id="c1-pump-real-groth16verifierv5-sol-lead" tabindex="-1">C1. Pump real Groth16VerifierV5.sol (lead) <a class="header-anchor" href="#c1-pump-real-groth16verifierv5-sol-lead" aria-label="Permalink to &quot;C1. Pump real Groth16VerifierV5.sol (lead)&quot;">​</a></h3><ul><li>Owner: <code>team-lead</code> + <code>circuits-eng</code></li><li>Pump from <code>arch-circuits/packages/circuits/ceremony/v5/Groth16VerifierV5.sol</code> to <code>arch-contracts/packages/contracts/src/Groth16VerifierV5.sol</code></li><li>Replaces existing <code>Groth16VerifierV5Stub.sol</code></li><li>Single commit on <code>feat/v5arch-contracts</code></li><li>Acceptance: contracts-eng&#39;s full forge test suite passes against the new verifier.</li></ul><h3 id="c2-real-diia-lotl-reflatten-flattener-eng" tabindex="-1">C2. Real-Diia LOTL reflatten (flattener-eng) <a class="header-anchor" href="#c2-real-diia-lotl-reflatten-flattener-eng" aria-label="Permalink to &quot;C2. Real-Diia LOTL reflatten (flattener-eng)&quot;">​</a></h3><ul><li>Owner: <code>flattener-eng</code></li><li>Re-run flattener against current EU LOTL snapshot</li><li>Compute <code>INITIAL_TRUST_ROOT</code> for deploy</li><li>Compute <code>INITIAL_POLICY_ROOT</code> (V5 default policy leaf hash)</li><li>Pump fresh <code>trusted-cas.json</code> + <code>root.json</code> to deploy fixtures</li><li>Acceptance: deterministic root regen succeeds; values match what circuits-eng&#39;s witness builder expects.</li></ul><h3 id="c3-base-sepolia-broadcast-deploy-contracts-eng" tabindex="-1">C3. Base Sepolia broadcast deploy (contracts-eng) <a class="header-anchor" href="#c3-base-sepolia-broadcast-deploy-contracts-eng" aria-label="Permalink to &quot;C3. Base Sepolia broadcast deploy (contracts-eng)&quot;">​</a></h3><ul><li>Owner: <code>contracts-eng</code></li><li>Tracker: Task #15</li><li>Pre-deploy checklist: <ul><li>Admin wallet funded with Base Sepolia ETH (≥ 0.001 ETH per dry-run estimate; more is safer)</li><li>Env vars set: <code>PRIVATE_KEY</code>, <code>BASESCAN_API_KEY</code>, <code>BASE_SEPOLIA_RPC_URL</code>, <code>INITIAL_TRUST_ROOT</code> (from C2), <code>INITIAL_POLICY_ROOT</code> (from C2), <code>MINT_DEADLINE</code> (Unix seconds, ≥ 6 months out)</li></ul></li><li>Deploy:<div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>forge script script/DeployV5.s.sol:DeployV5 \\</span></span>
<span class="line"><span>  --rpc-url $BASE_SEPOLIA_RPC_URL \\</span></span>
<span class="line"><span>  --broadcast --verify \\</span></span>
<span class="line"><span>  --etherscan-api-key $BASESCAN_API_KEY \\</span></span>
<span class="line"><span>  -vv</span></span></code></pre></div></li><li>Post-deploy: <ul><li>Capture deployed addresses</li><li>Verify on Basescan (PoseidonT3/T7 will need bytecode-only manual verification — flagged in contracts-eng&#39;s Task 15 prep)</li><li>Tag the deploy commit <code>v0.5.0-base-sepolia</code></li></ul></li><li>Acceptance: all 4 contracts deployed (Groth16VerifierV5, QKBRegistryV5, IdentityEscrowNFT, plus PoseidonT3/T7 sub-contracts), all verified on Basescan.</li></ul><h3 id="c4-pump-deployment-fixtures-lead" tabindex="-1">C4. Pump deployment fixtures (lead) <a class="header-anchor" href="#c4-pump-deployment-fixtures-lead" aria-label="Permalink to &quot;C4. Pump deployment fixtures (lead)&quot;">​</a></h3><ul><li>Owner: <code>team-lead</code></li><li>Write <code>fixtures/contracts/base-sepolia.json</code> with deployed addresses</li><li>Pump to web-eng worktree (<code>packages/sdk/src/deployments.ts</code> baseSepolia entry)</li><li>Pump to flattener-eng + circuits-eng for awareness</li><li>Acceptance: web-eng&#39;s V5 register flow can resolve <code>registryV5</code> address from <code>deployments.ts</code>.</li></ul><h3 id="c5-pump-zkey-verifier-urls-web-eng" tabindex="-1">C5. Pump zkey + verifier URLs (web-eng) <a class="header-anchor" href="#c5-pump-zkey-verifier-urls-web-eng" aria-label="Permalink to &quot;C5. Pump zkey + verifier URLs (web-eng)&quot;">​</a></h3><ul><li>Owner: <code>web-eng</code></li><li>Update <code>circuitArtifacts.ts</code> with R2 production zkey URL (<code>prove.zkqes.org/qkb-v5-final.zkey</code>)</li><li>Pump <code>verification_key.json</code> from final ceremony to <code>packages/sdk/fixtures/v5/</code> (replacing stub)</li><li>Real-fullProve E2E test (deferred from Task 13): wire up <code>e2e:real-prover</code> invocation that pulls real zkey, runs full prove, asserts byte-equality against the ceremony&#39;s final sample-proof</li><li>Acceptance: real-prover E2E passes against live R2 zkey; SDK + web tests still green.</li></ul><h3 id="phase-c-gate-to-phase-d" tabindex="-1">Phase C gate to Phase D <a class="header-anchor" href="#phase-c-gate-to-phase-d" aria-label="Permalink to &quot;Phase C gate to Phase D&quot;">​</a></h3><ul><li>Deploy successful + verified on Basescan</li><li>Fixtures pumped to all consumer worktrees</li><li>Real-prover E2E green</li><li>Admin wallet has remaining gas (for the founder dry-run in Phase D)</li></ul><hr><h2 id="phase-d-—-§9-4-acceptance-gate" tabindex="-1">Phase D — §9.4 acceptance gate <a class="header-anchor" href="#phase-d-—-§9-4-acceptance-gate" aria-label="Permalink to &quot;Phase D — §9.4 acceptance gate&quot;">​</a></h2><p><strong>Goal:</strong> Hard gate before public launch. Cross-package smoke against live Base Sepolia, validates every spec acceptance criterion.</p><p><strong>Wall estimate:</strong> ~1 day, lead-driven, multi-device.</p><h3 id="d1-founder-dry-run-lead-founder" tabindex="-1">D1. Founder dry-run (lead + founder) <a class="header-anchor" href="#d1-founder-dry-run-lead-founder" aria-label="Permalink to &quot;D1. Founder dry-run (lead + founder)&quot;">​</a></h3><ul><li>Owner: <code>team-lead</code> + <code>founder</code></li><li>Tracker: Task #18</li><li>Sequence: <ol><li>Founder generates fresh Diia QES on QKB/2.0 binding (real Diia mobile app)</li><li>Pumps <code>.p7s</code> to laptop</li><li>Visits <code>https://zkqes.org/ua/registerV5</code> (still on Fly during Phase D — GH Pages migration is Phase E)</li><li>Connects wallet (Sepolia)</li><li>Generates V5 binding via Step 2 → witness via build-witness-v5 → proof via SnarkjsWorkerProver against real zkey</li><li>Submits register tx → captures hash</li><li>Visits <code>/ua/mint</code> → mints IdentityEscrowNFT №1 → captures hash</li></ol></li><li>Captures: <ul><li>Register tx hash + gas used (must be ≤ 2.5M per spec)</li><li>Mint tx hash</li><li>Decoded <code>tokenURI(1)</code> SVG (must render civic-monumental certificate with real nullifier)</li></ul></li><li>Acceptance: full flow succeeds end-to-end; gas under cap; SVG renders correctly.</li></ul><h3 id="d2-multi-browser-desktop-smoke" tabindex="-1">D2. Multi-browser desktop smoke <a class="header-anchor" href="#d2-multi-browser-desktop-smoke" aria-label="Permalink to &quot;D2. Multi-browser desktop smoke&quot;">​</a></h3><ul><li>Owner: <code>team-lead</code></li><li>Repeat the founder flow&#39;s connect-and-prove path (mock-prover OK for repeat) on: <ul><li>Chromium (latest)</li><li>Firefox (latest)</li><li>Safari (macOS, latest)</li></ul></li><li>Acceptance: 3/3 browsers complete the prove + register UX without errors. Doesn&#39;t need to actually broadcast (one register per nullifier — keep the founder&#39;s as the canonical first mint).</li></ul><h3 id="d3-mobile-browser-flagship-gate-validation" tabindex="-1">D3. Mobile-browser flagship-gate validation <a class="header-anchor" href="#d3-mobile-browser-flagship-gate-validation" aria-label="Permalink to &quot;D3. Mobile-browser flagship-gate validation&quot;">​</a></h3><ul><li>Owner: <code>team-lead</code></li><li>Per spec acceptance criterion: full prove flow on Pixel 9 (Android 14+, Chrome 120+) AND iPhone 15 (iOS 17+, Safari) with <code>navigator.storage.persist()</code> granted.</li><li>Out-of-gate device validation: confirm rerouting UX on: <ul><li>Mid-range Android (UA-string-stub&#39;d or real device)</li><li>iOS in-app WebView (Telegram or Instagram)</li><li>Older browser (Chrome 110, Safari 16)</li></ul></li><li>Acceptance: flagships complete the prove flow (or skip prove via mock — the gate is about the page reaching prove without OOM, not necessarily completing the multi-minute compute on phone). Out-of-gate devices reroute to <code>/ua/use-desktop</code> cleanly.</li></ul><h3 id="d4-soundness-regression-suite" tabindex="-1">D4. Soundness regression suite <a class="header-anchor" href="#d4-soundness-regression-suite" aria-label="Permalink to &quot;D4. Soundness regression suite&quot;">​</a></h3><ul><li>Owner: <code>team-lead</code></li><li>Run the full V5 acceptance regression suite per spec §Acceptance criteria: <ul><li>Self-controlled <code>intSpki</code> paired with trusted-list entry → <code>BAD_TRUST_LIST</code></li><li>Same nullifier registered to two wallets → second tx reverts <code>NULLIFIER_USED</code></li><li>Binding with <code>policyLeafHash</code> not in policyRoot → <code>BAD_POLICY</code></li><li>Mismatched <code>signedAttrs.messageDigest</code> vs binding → circuit fails to satisfy</li><li>Public-signal hash hi/lo limbs mismatched against calldata → <code>BAD_*_HI</code> / <code>BAD_*_LO</code></li><li>SpkiCommit round-trip parity: leaf SPKI through contract <code>spkiCommit</code> matches circuit witness-side computation</li></ul></li><li>These are forge tests + e2e tests in respective packages; this gate just confirms they all run green against the live deploy state.</li><li>Acceptance: 100% pass.</li></ul><h3 id="phase-d-gate-to-phase-e" tabindex="-1">Phase D gate to Phase E <a class="header-anchor" href="#phase-d-gate-to-phase-e" aria-label="Permalink to &quot;Phase D gate to Phase E&quot;">​</a></h3><ul><li>D1 success: founder mint #1 on Sepolia, captures published privately for launch reveal</li><li>D2 + D3: cross-browser + flagship-mobile coverage clean</li><li>D4: full regression suite green</li><li>Critical: founder&#39;s mint is THE Sepolia launch artifact. From here, no more re-deploys to Sepolia (we don&#39;t want to invalidate this mint by replacing the registry).</li></ul><hr><h2 id="phase-e-—-frontend-cutover-public-launch" tabindex="-1">Phase E — Frontend cutover + public launch <a class="header-anchor" href="#phase-e-—-frontend-cutover-public-launch" aria-label="Permalink to &quot;Phase E — Frontend cutover + public launch&quot;">​</a></h2><p><strong>Goal:</strong> Move frontend from Fly (currently scaled-to-0) to GitHub Pages on <code>zkqes.org</code>. Execute public launch sequence.</p><p><strong>Wall estimate:</strong> 3-5 days, parallel-able sub-tasks.</p><h3 id="e1-github-pages-migration-lead" tabindex="-1">E1. GitHub Pages migration (lead) <a class="header-anchor" href="#e1-github-pages-migration-lead" aria-label="Permalink to &quot;E1. GitHub Pages migration (lead)&quot;">​</a></h3><ul><li>Owner: <code>team-lead</code></li><li>Tracker: Task #17</li><li>Deliverables: <ul><li>GitHub Actions workflow <code>actions/deploy-pages</code> triggered on push to main + post-merge from <code>feat/v5arch-web</code></li><li>Custom domain <code>zkqes.org</code> configured (DNS already on Cloudflare; just CNAME to <code>&lt;org&gt;.github.io</code>)</li><li>Auto-issued Let&#39;s Encrypt cert via GH Pages</li><li><code>coi-serviceworker</code> shim added if multithreaded snarkjs proving turns out to need <code>SharedArrayBuffer</code> (validate via desktop benchmark first; skip if single-threaded prove time is acceptable)</li><li>Fly app stays scaled-to-0 as ≥ 1-week rollback fallback</li></ul></li><li>Acceptance: <code>https://zkqes.org/</code> returns 200 from GH Pages; HTTPS valid; multithreaded prove either works (with shim) or single-threaded path is documented; rollback to Fly is a 2-record DNS flip in CF.</li></ul><h3 id="e2-branding-finalization-lead-founder" tabindex="-1">E2. Branding finalization (lead + founder) <a class="header-anchor" href="#e2-branding-finalization-lead-founder" aria-label="Permalink to &quot;E2. Branding finalization (lead + founder)&quot;">​</a></h3><ul><li>Owner: <code>founder</code> (decision) + <code>team-lead</code> (execution)</li><li>Tracker: Task #21</li><li>Founder decides: <ul><li>Lock zk-QES (the protocol) vs zkqes (the project) framing in spec / README / <code>BRAND.md</code></li><li>Or leave at marketing-doc level only</li></ul></li><li>If locking: spec amendment + README update + marketer drafts updated to match</li><li>Acceptance: framing decision made, propagated to all surfaces (or explicitly held at marketing-only).</li></ul><h3 id="e3-marketer-drafts-user-review-founder" tabindex="-1">E3. Marketer drafts user review (founder) <a class="header-anchor" href="#e3-marketer-drafts-user-review-founder" aria-label="Permalink to &quot;E3. Marketer drafts user review (founder)&quot;">​</a></h3><ul><li>Owner: <code>founder</code></li><li>Tracker: Task #20</li><li>Founder reads 6 drafts at <code>docs/marketing/2026-04-29-launch-drafts/</code>: <ul><li><code>positioning.md</code>, <code>launch-sequence.md</code>, <code>x-thread-launch.md</code>, <code>hn-post.md</code>, <code>faq.md</code>, <code>pre-launch-tease-1.md</code></li></ul></li><li>Decides on: <ul><li>Repo URL (currently placeholder <code>github.com/qkb-eth/zkqes</code>)</li><li>HN title pick (3 options offered)</li><li>Tease draft pick (A / B / C variants)</li><li>Audit framing terminology (currently &quot;scope letter / pre-print / pending&quot;)</li></ul></li><li>Marketer applies decisions in a follow-up commit</li><li>Acceptance: 6 drafts finalized; ready to publish on launch day.</li></ul><h3 id="e4-pre-launch-tease-t-2-weeks-before-launch-event" tabindex="-1">E4. Pre-launch tease (T-2 weeks before launch event) <a class="header-anchor" href="#e4-pre-launch-tease-t-2-weeks-before-launch-event" aria-label="Permalink to &quot;E4. Pre-launch tease (T-2 weeks before launch event)&quot;">​</a></h3><ul><li>Owner: <code>founder</code></li><li>Single quotable paragraph from <code>pre-launch-tease-1.md</code></li><li>Posted to founder&#39;s existing social profile (X mainly)</li><li>No product reveal — sets up the announcement to come</li><li>Acceptance: tease lands; quotable; doesn&#39;t preempt the launch reveal.</li></ul><h3 id="e5-reveal-t-1-week-before-launch" tabindex="-1">E5. Reveal (T-1 week before launch) <a class="header-anchor" href="#e5-reveal-t-1-week-before-launch" aria-label="Permalink to &quot;E5. Reveal (T-1 week before launch)&quot;">​</a></h3><ul><li>Owner: <code>founder</code> + <code>marketer</code></li><li>Public spec reveal: the 2026-04-29 V5 architecture spec is published with ceremony attestation chain visible</li><li>Repo public on GitHub (if not already)</li><li>Open-source from day-one principle: README + LICENSE + CONTRIBUTING.md visible</li><li>Acceptance: anyone can read the spec, browse the repo, verify the ceremony attestations, see the deployed contracts on Basescan.</li></ul><h3 id="e6-launch-day" tabindex="-1">E6. Launch day <a class="header-anchor" href="#e6-launch-day" aria-label="Permalink to &quot;E6. Launch day&quot;">​</a></h3><ul><li>Owner: <code>founder</code></li><li>Sequence (~1 hour): <ol><li>Founder mint #1 on Sepolia is already done from Phase D (or do it on launch day if you waited)</li><li>Founder posts the launch X thread (10 tweets per <code>x-thread-launch.md</code> final)</li><li>Founder posts to Hacker News with the agreed title from <code>hn-post.md</code></li><li>Founder posts to selected Ukrainian crypto Telegram / X channels per <code>launch-sequence.md</code></li><li>Status page on <code>/ceremony</code> shows complete chain; founder mint NFT visible on OpenSea testnet</li></ol></li><li>Acceptance: launch lands; community responds; first non-founder Ukrainian mint within 24-48h is the social proof gate.</li></ul><h3 id="e7-post-launch-monitoring-t-1-week" tabindex="-1">E7. Post-launch monitoring (T+1 week) <a class="header-anchor" href="#e7-post-launch-monitoring-t-1-week" aria-label="Permalink to &quot;E7. Post-launch monitoring (T+1 week)&quot;">​</a></h3><ul><li>Owner: <code>team-lead</code></li><li>Watch: <ul><li>Mint count on Sepolia</li><li>Registry interaction telemetry</li><li>Any error reports (community channels, GitHub issues)</li><li>Mobile flagship-gate UX feedback (does the rerouting page work cleanly?)</li></ul></li><li>Triage gate to Phase F (mainnet): ≥ 1 week of stable Sepolia operation with no soundness or UX-breaking incidents</li><li>Acceptance: 1-week soak completes without rollback or critical fixes.</li></ul><h3 id="phase-e-gate-to-phase-f" tabindex="-1">Phase E gate to Phase F <a class="header-anchor" href="#phase-e-gate-to-phase-f" aria-label="Permalink to &quot;Phase E gate to Phase F&quot;">​</a></h3><ul><li>1-week Sepolia stable</li><li>Founder mint visible + decoded SVG correct</li><li>Audit complete OR explicit decision to ship without (audit terminology in marketing FAQ matches reality)</li><li>No critical UX bugs surfaced by community</li></ul><hr><h2 id="phase-f-—-base-mainnet-separately-gated" tabindex="-1">Phase F — Base mainnet (separately gated) <a class="header-anchor" href="#phase-f-—-base-mainnet-separately-gated" aria-label="Permalink to &quot;Phase F — Base mainnet (separately gated)&quot;">​</a></h2><p><strong>Goal:</strong> Production mainnet deploy. Real ETH for gas, real money behind the registry.</p><p><strong>Wall estimate:</strong> 1-2 days deploy + ongoing operations.</p><h3 id="f1-mainnet-deploy-contracts-eng" tabindex="-1">F1. Mainnet deploy (contracts-eng) <a class="header-anchor" href="#f1-mainnet-deploy-contracts-eng" aria-label="Permalink to &quot;F1. Mainnet deploy (contracts-eng)&quot;">​</a></h3><ul><li>Same <code>DeployV5.s.sol</code> script, mainnet RPC + mainnet admin private key</li><li>Pre-deploy: admin wallet funded with mainnet ETH (≥ 0.05 ETH); BASESCAN_API_KEY for verification; INITIAL_TRUST_ROOT + INITIAL_POLICY_ROOT same as Sepolia (or refreshed if EU LOTL rotated)</li><li>Same <code>forge script ... --broadcast --verify</code></li><li>Tag: <code>v1.0.0-base-mainnet</code></li><li>Acceptance: 4 contracts deployed + verified.</li></ul><h3 id="f2-founder-mint-1-on-mainnet" tabindex="-1">F2. Founder mint #1 on mainnet <a class="header-anchor" href="#f2-founder-mint-1-on-mainnet" aria-label="Permalink to &quot;F2. Founder mint #1 on mainnet&quot;">​</a></h3><ul><li>Owner: <code>founder</code></li><li>Real on-mainnet mint (the actual production launch event)</li><li>Captures: register tx, mint tx, tokenURI(1) SVG</li><li>These are the artifacts for the mainnet announcement</li><li>Acceptance: NFT №1 minted to founder wallet; Basescan shows minted; OpenSea (mainnet) shows certificate.</li></ul><h3 id="f3-public-mainnet-announcement" tabindex="-1">F3. Public mainnet announcement <a class="header-anchor" href="#f3-public-mainnet-announcement" aria-label="Permalink to &quot;F3. Public mainnet announcement&quot;">​</a></h3><ul><li>Owner: <code>founder</code> + <code>marketer</code></li><li>Updated launch thread + HN post pointing at mainnet</li><li>Sepolia phase becomes the historical staging</li><li>Acceptance: mainnet launch lives.</li></ul><h3 id="f4-gated-by-founder-explicit-go-ahead" tabindex="-1">F4. Gated by founder explicit go-ahead <a class="header-anchor" href="#f4-gated-by-founder-explicit-go-ahead" aria-label="Permalink to &quot;F4. Gated by founder explicit go-ahead&quot;">​</a></h3><p>Phase F is <strong>NOT auto-triggered</strong> by Phase E. Founder explicitly decides when to flip. This plan recommends ≥ 1 week Sepolia stable + audit closed (or documented as out-of-scope) before flipping.</p><hr><h2 id="risks-mitigations" tabindex="-1">Risks + mitigations <a class="header-anchor" href="#risks-mitigations" aria-label="Permalink to &quot;Risks + mitigations&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Risk</th><th>Likelihood</th><th>Mitigation</th></tr></thead><tbody><tr><td>Ceremony contributor goes silent mid-chain</td><td>Medium</td><td>48h SLA per contributor; founder skips and recruits replacement; chain integrity unaffected</td></tr><tr><td>Beacon block reorg</td><td>Low</td><td>Use a 12-block-confirmed block hash; reorg risk on Ethereum L1 at 12+ confirmations is effectively zero</td></tr><tr><td>pot23 file actually pot28 (mislabeled)</td><td>Low</td><td>Verified at A2 setup time before round-0; if mismatch, re-fetch from canonical Hermez source</td></tr><tr><td>Mobile flagship gate fails on real Pixel 9 / iPhone 15</td><td>Medium</td><td>Phase D flushes this; if either fails, narrow gate further (e.g., &quot;Pixel 9 Pro only&quot;), or surface as known limit and route everyone to desktop</td></tr><tr><td>Real-prover E2E fails with R2-hosted zkey</td><td>Low</td><td>Phase C5 catches this before Phase D; falls back to absolute-path zkey for now if R2 streaming is broken</td></tr><tr><td>Audit not complete by Phase F</td><td>High (likely)</td><td>Document as &quot;audit pre-print pending&quot; in launch copy + FAQ; keep Sepolia as the vetting ground</td></tr><tr><td>Community contribution to ceremony swamps coordination capacity</td><td>Low</td><td>Cap at 10 trusted core; Twitter call only after core is confirmed; can extend post-beacon if anyone wants to attest a derivative chain</td></tr></tbody></table><hr><h2 id="open-decisions-founder-side" tabindex="-1">Open decisions (founder-side) <a class="header-anchor" href="#open-decisions-founder-side" aria-label="Permalink to &quot;Open decisions (founder-side)&quot;">​</a></h2><p>These are the gating items not in any worker&#39;s scope:</p><ol><li><strong>§11 ceremony go-ahead.</strong> Required to enter Phase B.</li><li><strong>Recruitment list.</strong> Founder-driven; report back when 5+ confirmed.</li><li><strong>Branding lock (#21).</strong> zk-QES vs zkqes framing in formal docs vs marketing-only.</li><li><strong>Marketer drafts review (#20).</strong> 7 sub-decisions across 6 files.</li><li><strong>Pre-launch tease timing.</strong> T-2 weeks before launch event; defines launch date countdown.</li><li><strong>Audit posture for launch.</strong> Ship-without-audit + clear FAQ language, or hold for pre-print first.</li><li><strong>Mainnet flip (Phase F).</strong> When (and whether) to graduate from Sepolia.</li></ol><hr><h2 id="tracker-references" tabindex="-1">Tracker references <a class="header-anchor" href="#tracker-references" aria-label="Permalink to &quot;Tracker references&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Phase</th><th>Tasks</th></tr></thead><tbody><tr><td>A</td><td>#27 (web /ceremony page); A2 + A4 = new tasks at dispatch time</td></tr><tr><td>B</td><td>#8 (circuits §11 ceremony)</td></tr><tr><td>C</td><td>#15 (contracts Base Sepolia deploy); pumping = lead inline</td></tr><tr><td>D</td><td>#18 (Sepolia E2E §9.4 acceptance gate)</td></tr><tr><td>E</td><td>#17 (GH Pages migration); #20 (marketer drafts review); #21 (branding finalization); #19 (spec review — close)</td></tr><tr><td>F</td><td>New task at gate-flip time</td></tr></tbody></table><p>Closed tasks for the V5 architecture (1-26 sans pending): see team todo list.</p><hr><h2 id="end-state" tabindex="-1">End-state <a class="header-anchor" href="#end-state" aria-label="Permalink to &quot;End-state&quot;">​</a></h2><p><strong>Sepolia public launch (end of Phase E):</strong></p><ul><li><code>https://zkqes.org/</code> live on GH Pages</li><li>V5 contracts deployed on Base Sepolia, all verified on Basescan</li><li>Final production zkey on <code>prove.zkqes.org/qkb-v5-final.zkey</code></li><li>7-10 contributor ceremony attested + chain published</li><li>Founder mint #1 visible on Sepolia</li><li>Public spec + repo + LICENSE</li><li>Launch thread + HN post + community channels live</li><li>1-week soak gate before Phase F</li></ul><p><strong>Mainnet (end of Phase F):</strong></p><ul><li>Same end-state on Base mainnet</li><li>Sepolia stays as historical staging</li><li>Audit pre-print or completed audit attached to FAQ</li></ul><p>That is V1 of the project.</p>`,119)])])}const m=a(r,[["render",l]]);export{h as __pageData,m as default};
